import { Component, ChangeDetectionStrategy, signal, inject, effect, OnInit, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DataService, UserData } from './services/data.service';
import { ChatService } from './services/chat.service';
import { LoginComponent } from './components/login/login.component';
import { CalculatorComponent } from './components/calculator/calculator.component';
import { AdminPanelComponent } from './components/admin-panel/admin-panel.component';
import { ScannerComponent } from './components/scanner/scanner.component';
import { ChatComponent } from './components/chat/chat.component'; 
import { StoreIconComponent } from './components/icons/store-icon.component';
import { UsersIconComponent } from './components/icons/users-icon.component';
import { CalculatorIconComponent } from './components/icons/calculator-icon.component';
import { LogoutIconComponent } from './components/icons/logout-icon.component';
import { CameraIconComponent } from './components/icons/camera-icon.component';
import { MessageCircleIconComponent } from './components/icons/message-circle-icon.component';
import { Title } from '@angular/platform-browser';

type AppState = 'initializing' | 'error' | 'login' | 'pin-lock' | 'set-pin' | 'app' | 'scanner' | 'chat';
const SESSION_KEY = 'fw_user_session';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    LoginComponent,
    CalculatorComponent,
    AdminPanelComponent,
    ScannerComponent,
    ChatComponent,
    StoreIconComponent,
    UsersIconComponent,
    CalculatorIconComponent,
    LogoutIconComponent,
    CameraIconComponent,
    MessageCircleIconComponent
  ],
})
export class AppComponent implements OnInit {
  private dataService = inject(DataService);
  private chatService = inject(ChatService);
  private titleService = inject(Title);

  appState = signal<AppState>('initializing');
  private previousState: AppState = 'app';

  isAdmin = signal(false);
  currentUser = signal<UserData | null>(null);
  activeTab = signal<'calc' | 'admin'>('calc');
  loginError = signal<string | null>(null);
  isLoggingIn = signal(false);

  adminSettings = this.dataService.adminSettings;
  users = this.dataService.allUsers;

  userExpiryStatus = computed(() => {
    const user = this.currentUser();
    // Don't show status if no user OR if it is Admin
    if (!user || this.isAdmin()) {
        return null;
    }

    if (!user.expiresAt) {
      return { text: 'သက်တမ်းအကန့်အသတ်မရှိ', colorClass: 'text-emerald-400 bg-emerald-500/10' };
    }

    const expiryDate = new Date(user.expiresAt);
    const now = new Date();
    expiryDate.setHours(0, 0, 0, 0);
    now.setHours(0, 0, 0, 0);

    const diffTime = expiryDate.getTime() - now.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) {
      return { text: `သက်တမ်းကုန်ဆုံး`, colorClass: 'text-rose-400 bg-rose-500/10' };
    }
    if (diffDays === 0) {
       return { text: `ယနေ့ သက်တမ်းကုန်မည်`, colorClass: 'text-amber-400 bg-amber-500/10' };
    }
    if (diffDays <= 7) {
      return { text: `${diffDays} ရက်အတွင်း ကုန်ဆုံးမည်`, colorClass: 'text-amber-400 bg-amber-500/10' };
    }
    return { text: `${diffDays} ရက်အတွင်း ကုန်ဆုံးမည်`, colorClass: 'text-slate-400 bg-slate-500/10' };
  });

  constructor() {
    effect(() => {
      const settings = this.adminSettings();
      if (settings?.shopName) {
          this.titleService.setTitle(settings.shopName);
      }
    });
  }

  async ngOnInit() {
    this.appState.set('initializing');
    await this.dataService.initialize();

    const sessionData = localStorage.getItem(SESSION_KEY);
    if (sessionData) {
      try {
        const user: UserData = JSON.parse(sessionData);

        if (user.expiresAt && new Date(user.expiresAt) < new Date()) {
          this.handleLogout('Key သက်တမ်းကုန်နေပါသည်');
          return;
        }

        const deviceId = this.getDeviceId();
        if (user.deviceId !== deviceId) {
          this.handleLogout('ဤအကောင့်သည် အခြားစက်အတွက်သာဖြစ်သည်');
          return;
        }

        this.currentUser.set(user);
        this.isAdmin.set(false);

        if (user.pin) {
          this.appState.set('pin-lock');
        } else {
          this.appState.set('set-pin');
        }
      } catch (e) {
        localStorage.removeItem(SESSION_KEY);
        this.appState.set('login');
      }
    } else {
        const initState = this.dataService.adminSettings() ? 'login' : 'error';
        this.appState.set(initState);
    }
  }

  retry() {
    location.reload();
  }

  private getDeviceId(): string {
    let deviceId = localStorage.getItem('fw_device_id');
    if (!deviceId) {
      deviceId = crypto.randomUUID();
      localStorage.setItem('fw_device_id', deviceId);
    }
    return deviceId;
  }

  handleLogin(loginInput: string) {
    this.isLoggingIn.set(true);
    this.loginError.set(null);

    const input = loginInput.trim();
    const settings = this.adminSettings();

    if (settings && input.toUpperCase() === settings.masterPass.toUpperCase()) {
      this.isAdmin.set(true);

      // Create a virtual user for Admin to enable chat features
      // This ID is constant so chat history is preserved for Admin
      const adminUser: UserData = {
          id: 'ADMIN_ACCOUNT',
          name: settings.shopName || 'Admin',
          key: 'ADMIN',
          deviceId: 'ADMIN_DEVICE',
          createdAt: new Date().toISOString(),
          expiresAt: null
      };
      this.currentUser.set(adminUser);

      this.appState.set('app');
      this.activeTab.set('calc');
      this.isLoggingIn.set(false);
      return;
    }

    try {
      const user: UserData = JSON.parse(atob(input));

      if (!user || !user.id || !user.key || !user.createdAt) {
        throw new Error('Invalid token structure');
      }

      if (user.expiresAt && new Date(user.expiresAt) < new Date()) {
        this.loginError.set('ဤ Login Token သည် သက်တမ်းကုန်နေပါသည်');
        this.isLoggingIn.set(false);
        return;
      }

      const deviceId = this.getDeviceId();
      const sessionUser: UserData = { ...user, deviceId: deviceId };
      localStorage.setItem(SESSION_KEY, JSON.stringify(sessionUser));

      this.currentUser.set(sessionUser);
      this.isAdmin.set(false);
      this.appState.set('set-pin');
      this.isLoggingIn.set(false);

    } catch (error) {
      this.loginError.set('Login Token မမှန်ပါ။ Admin ထံမှရသော စာသားအားလုံးကို copy ကူးပြီးထည့်ပါ');
      this.isLoggingIn.set(false);
    }
  }

  handlePinLogin(pin: string) {
    this.isLoggingIn.set(true);
    this.loginError.set(null);
    const user = this.currentUser();

    if (user && user.pin === pin) {
      this.appState.set('app');
    } else {
      this.loginError.set('PIN မမှန်ပါ။');
    }
    this.isLoggingIn.set(false);
  }

  handleSetPin(pin: string) {
    const user = this.currentUser();
    if (!user) return;

    const updatedUser = { ...user, pin };
    localStorage.setItem(SESSION_KEY, JSON.stringify(updatedUser));
    this.currentUser.set(updatedUser);
    this.appState.set('app');
  }

  handleSkipPin() {
    this.appState.set('app');
  }

  handleLogout(error: string | null = null) {
    localStorage.removeItem(SESSION_KEY);
    this.currentUser.set(null);
    this.appState.set('login');
    this.isAdmin.set(false);
    this.loginError.set(error);
  }

  toggleTab() {
    this.activeTab.update(current => current === 'calc' ? 'admin' : 'calc');
  }

  openScanner() {
    if (this.appState() === 'app' || this.appState() === 'chat') {
      if (this.appState() !== 'scanner') {
        this.previousState = this.appState();
        this.appState.set('scanner');
      }
    }
  }

  closeScanner() {
    this.appState.set(this.previousState);
  }

  openChat() {
    if (this.appState() === 'app') {
      this.previousState = 'app';
      this.appState.set('chat');
    }
  }

  closeChat() {
    this.appState.set(this.previousState);
  }

  clearLoginError() {
      this.loginError.set(null);
  }

  // Handle when Scanner finds a User ID via QR
  async handleUserFound(contact: {id: string, name: string}) {
      const me = this.currentUser();
      if (!me) return;

      if (contact.id === me.id) {
          alert('You scanned your own ID.');
          this.closeScanner();
          return;
      }

      // If scanning a mobile QR, name might be 'Mobile User'. 
      // We show the ID for confirmation if the name is generic.
      const displayName = contact.name === 'Mobile User' ? `ID: ${contact.id}` : contact.name;
      const confirmAdd = confirm(`Send friend request to ${displayName}?`);

      if (confirmAdd) {
          // Send request logic via chat service
          await this.chatService.sendFriendRequest(me.id, me.name, contact.id);
          alert('Request Sent!');
          this.appState.set('chat'); 
      } else {
          this.closeScanner();
      }
  }
}

import { Injectable, signal, effect } from '@angular/core';
import { initializeApp, FirebaseApp } from 'firebase/app';
import { getDatabase, ref, push, onValue, Database, off, serverTimestamp, set, get, remove, update } from 'firebase/database';

export interface ChatMessage {
  id?: string;
  text?: string; // Content payload (text or base64 image)
  imageUrl?: string; // For backward compatibility or distinct field
  type?: 'text' | 'image';
  senderId: string;
  timestamp: number;
}

export interface ChatContact {
  userId: string;
  name: string;
  lastMessage?: string;
  lastTimestamp?: number;
  chatId: string;
}

export interface FriendRequest {
  senderId: string;
  senderName: string;
  timestamp: number;
}

@Injectable({
  providedIn: 'root'
})
export class ChatService {
  private app: FirebaseApp | undefined;
  private db: Database | undefined;

  // Signals
  contacts = signal<ChatContact[]>([]);
  incomingRequests = signal<FriendRequest[]>([]); 
  activeMessages = signal<ChatMessage[]>([]);
  isConnected = signal(false);

  constructor() {
    this.initFirebase();
  }

  private initFirebase() {
    const firebaseConfig = {
      apiKey: "AIzaSyAas8VrbH-tb6FWQRa4JrqEJEZcsOKcwEo",
      authDomain: "d-management-6bd74.firebaseapp.com",
      databaseURL: "https://d-management-6bd74-default-rtdb.asia-southeast1.firebasedatabase.app",
      projectId: "d-management-6bd74",
      storageBucket: "d-management-6bd74.firebasestorage.app",
      messagingSenderId: "881446635711",
      appId: "1:881446635711:web:cf755a10a36adfbd339e0a",
      measurementId: "G-GVF6DEGVJX"
    };

    try {
      this.app = initializeApp(firebaseConfig);
      this.db = getDatabase(this.app);

      // Monitor connection status properly
      const connectedRef = ref(this.db, '.info/connected');
      onValue(connectedRef, (snap) => {
        this.isConnected.set(!!snap.val());
      });

    } catch (error) {
      console.error('Firebase Init Error:', error);
      this.isConnected.set(false);
    }
  }

  // --- 1. Listeners ---

  listenToUserData(myUserId: string) {
    if (!this.db || !myUserId) return;

    // Listen to Contacts
    const contactsRef = ref(this.db, `users/${myUserId}/contacts`);
    onValue(contactsRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list: ChatContact[] = Object.values(data);
        list.sort((a, b) => (b.lastTimestamp || 0) - (a.lastTimestamp || 0));
        this.contacts.set(list);
      } else {
        this.contacts.set([]);
      }
    });

    // Listen to Incoming Requests
    const requestsRef = ref(this.db, `requests/${myUserId}`);
    onValue(requestsRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const list: FriendRequest[] = Object.values(data);
        // Sort by newest
        list.sort((a, b) => b.timestamp - a.timestamp);
        this.incomingRequests.set(list);
      } else {
        this.incomingRequests.set([]);
      }
    });
  }

  // --- 2. Friend Request Logic ---

  async sendFriendRequest(myId: string, myName: string, targetId: string) {
    if (!this.db) return;

    if (myId === targetId) throw new Error("Cannot add yourself.");

    // Write to target's request bucket
    const requestRef = ref(this.db, `requests/${targetId}/${myId}`);

    await set(requestRef, {
      senderId: myId,
      senderName: myName,
      timestamp: Date.now()
    });
  }

  async acceptFriendRequest(myId: string, myName: string, request: FriendRequest) {
    if (!this.db) return;

    const otherId = request.senderId;
    const otherName = request.senderName;
    const chatId = [myId, otherId].sort().join('_'); // Consistent Chat ID

    const updates: any = {};

    // 1. Add to My Contacts
    updates[`users/${myId}/contacts/${otherId}`] = {
      userId: otherId,
      name: otherName,
      chatId: chatId,
      lastTimestamp: Date.now()
    };

    // 2. Add to Other's Contacts
    updates[`users/${otherId}/contacts/${myId}`] = {
      userId: myId,
      name: myName,
      chatId: chatId,
      lastTimestamp: Date.now()
    };

    // 3. Delete the Request
    updates[`requests/${myId}/${otherId}`] = null;

    // Perform atomic update
    await update(ref(this.db), updates);
  }

  async rejectFriendRequest(myId: string, senderId: string) {
    if (!this.db) return;
    await remove(ref(this.db, `requests/${myId}/${senderId}`));
  }

  // --- 3. Messaging ---

  listenToMessages(chatId: string) {
    if (!this.db || !chatId) return;
    this.activeMessages.set([]); 

    const messagesRef = ref(this.db, `messages/${chatId}`);

    onValue(messagesRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const msgList: ChatMessage[] = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        })).sort((a, b) => a.timestamp - b.timestamp);
        this.activeMessages.set(msgList);
      } else {
        this.activeMessages.set([]);
      }
    });
  }

  stopListeningMessages(chatId: string) {
    if (!this.db || !chatId) return;
    off(ref(this.db, `messages/${chatId}`));
  }

  async sendMessage(chatId: string, content: string, senderId: string, myId: string, otherId: string, type: 'text' | 'image' = 'text') {
    if (!this.db) return;

    const messageData: any = {
      senderId,
      timestamp: serverTimestamp(),
      type
    };

    if (type === 'image') {
      messageData.imageUrl = content;
      messageData.text = 'Sent an image'; // Fallback text for notifications
    } else {
      messageData.text = content;
    }

    // 1. Push Message
    await push(ref(this.db, `messages/${chatId}`), messageData);

    // 2. Update Last Message for both users
    const db = this.db;
    const lastMsgPreview = type === 'image' ? 'Sent an image' : content;

    const updates: any = {};
    updates[`users/${myId}/contacts/${otherId}/lastMessage`] = lastMsgPreview;
    updates[`users/${myId}/contacts/${otherId}/lastTimestamp`] = serverTimestamp();
    updates[`users/${otherId}/contacts/${myId}/lastMessage`] = lastMsgPreview;
    updates[`users/${otherId}/contacts/${myId}/lastTimestamp`] = serverTimestamp();

    await update(ref(db), updates);
  }
}

